INSERT INTO `v1_513452ff58c61db7a127f52b9e88d57d1e6e4f26d9b892a8e6434e0ef1ff0474` VALUES (1, "イベントでは、特別なストーリーをお楽しみいただけます。\n閲覧可能なストーリーを読むと、次のお話が解放されていきますよ。\nストーリーの閲覧によって達成されるミッションもあるのだとか。", 1011, 1, 1);
INSERT INTO `v1_513452ff58c61db7a127f52b9e88d57d1e6e4f26d9b892a8e6434e0ef1ff0474` VALUES (2, "イベントクエストやボスバトルに挑戦してみましょう。ボスバトルは\n特定のイベントストーリーを閲覧するか、イベントクエスト・ボス画面で\n「解放する」を選択すると挑戦可能になりますよ。", 1021, 2, 1);
INSERT INTO `v1_513452ff58c61db7a127f52b9e88d57d1e6e4f26d9b892a8e6434e0ef1ff0474` VALUES (4, "報酬交換では「イベント報酬券」と様々なアイテムを交換できます。\n目玉となるリセット対象報酬を引くことで、より多くのアイテムが\n獲得できる次のラインナップへと進めるそうです。", 1041, 4, 1);
INSERT INTO `v1_513452ff58c61db7a127f52b9e88d57d1e6e4f26d9b892a8e6434e0ef1ff0474` VALUES (5, "ボスバトルには３種の難易度がございます。\n各難易度ごとにボスの強さやバトルの特徴が異なりますので、\n準備をしっかりして、気を引き締めて挑みましょう。", 1051, 5, 1);
INSERT INTO `v1_513452ff58c61db7a127f52b9e88d57d1e6e4f26d9b892a8e6434e0ef1ff0474` VALUES (1, "イベントでは、特別なストーリーをお楽しみいただけます。\n閲覧可能なストーリーを読むと、次のお話が解放されていきますよ。\nストーリーの閲覧によって達成されるミッションもあるのだとか。", 2011, 1, 2);
INSERT INTO `v1_513452ff58c61db7a127f52b9e88d57d1e6e4f26d9b892a8e6434e0ef1ff0474` VALUES (2, "イベントクエストやボスバトルに挑戦してみましょう。ボスバトルは\n特定のイベントストーリーを閲覧するか、イベントクエスト・ボス画面で\n「解放する」を選択すると挑戦可能になりますよ。", 2021, 2, 2);
INSERT INTO `v1_513452ff58c61db7a127f52b9e88d57d1e6e4f26d9b892a8e6434e0ef1ff0474` VALUES (4, "報酬交換では「イベント報酬券」と様々なアイテムを交換できます。\n目玉となるリセット対象報酬を引くことで、より多くのアイテムが\n獲得できる次のラインナップへと進めるそうです。", 2041, 4, 2);
INSERT INTO `v1_513452ff58c61db7a127f52b9e88d57d1e6e4f26d9b892a8e6434e0ef1ff0474` VALUES (5, "ボスバトルには２種の難易度がございます。\n各難易度ごとにボスの強さやバトルの特徴が異なりますので、\n準備をしっかりして、気を引き締めて挑みましょう。", 2051, 5, 2);
